namespace sv_29fc3e824fba45c59008af8e307b0bfe.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_29fc3e824fba45c59008af8e307b0bfe.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-name"># @Channel.Name</div>
    <div class="channel-description">@TruncatedDescription</div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..40] + "…"
            : Channel.Description;

    private async Task OnClick() => await OnSelected.InvokeAsync(Channel);
}

@using sv_29fc3e824fba45c59008af8e307b0bfe.Services

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = new();
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

@using sv_29fc3e824fba45c59008af8e307b0bfe.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" @onclick="() => OnReact.InvokeAsync(new ReactionRequest(Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <div class="thread-link" @onclick="() => OnOpenThread.InvokeAsync(Message)">
            @ThreadReplyCount replies
        </div>
    }

    @if (showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync(Message)" title="Reply in thread">Reply</button>
            <div class="emoji-picker-wrapper">
                <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">React</button>
                @if (showEmojiPicker)
                {
                    <div class="emoji-picker">
                        @foreach (var emoji in CommonEmojis)
                        {
                            <span class="emoji-option" @onclick="() => SelectEmoji(emoji)">@emoji</span>
                        }
                    </div>
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ThreadReplyCount { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<ReactionRequest> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] CommonEmojis = { "👍", "❤️", "😂", "🎉", "🤔", "👀" };

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync(new ReactionRequest(Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }

    public record ReactionRequest(int MessageId, string Emoji);
}

@using sv_29fc3e824fba45c59008af8e307b0bfe.Services
@inject IJSRuntime JS

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @foreach (var message in Messages)
            {
                <MessageItem Message="message"
                             ThreadReplyCount="GetThreadReplyCount(message.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSend="OnSendMessage" />
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<MessageItem.ReactionRequest> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;
    private bool scrolledToBottom = true;

    private int GetThreadReplyCount(int messageId)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
        return summary?.ReplyCount ?? 0;
    }

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop <= 0 && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (scrolledToBottom)
        {
            await JS.InvokeVoidAsync("eval",
                "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
        }
    }
}

@using sv_29fc3e824fba45c59008af8e307b0bfe.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="message-author">@RootMessage.Author</span>
            <p class="message-content">@RootMessage.Content</p>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply-item">
                    <div class="message-header">
                        <span class="message-author">@reply.Author</span>
                        <span class="message-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="message-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d");
    }
}

@page "/chat"
@using sv_29fc3e824fba45c59008af8e307b0bfe.Services
@using sv_29fc3e824fba45c59008af8e307b0bfe.Components.Chat
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout @(isThreadOpen ? "thread-open" : "")">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannel?.Id"
                    OnChannelSelected="SelectChannel" />

    <MessageArea Channel="selectedChannel"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 IsLoadingMore="isLoadingMore"
                 OnOpenThread="OpenThread"
                 OnReact="HandleReaction"
                 OnSendMessage="SendMessage"
                 OnLoadMore="LoadMoreMessages" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = new();
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private List<ThreadSummary> threadSummaries = new();
    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();
    private bool isLoadingMore;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
        CloseThreadSync();
        StateHasChanged();
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
        }

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
        StateHasChanged();
    }

    private async Task OpenThread(Message message)
    {
        threadRootMessage = message;
        threadReplies = await ChatService.GetThreadAsync(message.Id);
        isThreadOpen = true;
        StateHasChanged();
    }

    private void CloseThreadSync()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
    }

    private Task CloseThread()
    {
        CloseThreadSync();
        StateHasChanged();
        return Task.CompletedTask;
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || selectedChannel is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        StateHasChanged();
    }

    private async Task HandleReaction(MessageItem.ReactionRequest request)
    {
        await ChatService.AddReactionAsync(request.MessageId, request.Emoji);
        // Refresh messages to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
        StateHasChanged();
    }
}

namespace sv_29fc3e824fba45c59008af8e307b0bfe.Services;

