@page "/chat"
@using sv_29fc3e824fba45c59008af8e307b0bfe.Services
@using sv_29fc3e824fba45c59008af8e307b0bfe.Components.Chat
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Team Chat</PageTitle>

<div class="chat-layout @(isThreadOpen ? "thread-open" : "")">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="selectedChannel?.Id"
                    OnChannelSelected="SelectChannel" />

    <MessageArea Channel="selectedChannel"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 IsLoadingMore="isLoadingMore"
                 OnOpenThread="OpenThread"
                 OnReact="HandleReaction"
                 OnSendMessage="SendMessage"
                 OnLoadMore="LoadMoreMessages" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = new();
    private Channel? selectedChannel;
    private List<Message> messages = new();
    private List<ThreadSummary> threadSummaries = new();
    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();
    private bool isLoadingMore;
    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        selectedChannel = channel;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
        CloseThreadSync();
        StateHasChanged();
    }

    private async Task LoadMoreMessages()
    {
        if (selectedChannel is null || isLoadingMore) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
        }

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessage(string content)
    {
        if (selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
        messages.Add(msg);
        StateHasChanged();
    }

    private async Task OpenThread(Message message)
    {
        threadRootMessage = message;
        threadReplies = await ChatService.GetThreadAsync(message.Id);
        isThreadOpen = true;
        StateHasChanged();
    }

    private void CloseThreadSync()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = new();
    }

    private Task CloseThread()
    {
        CloseThreadSync();
        StateHasChanged();
        return Task.CompletedTask;
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || selectedChannel is null) return;
        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        StateHasChanged();
    }

    private async Task HandleReaction(MessageItem.ReactionRequest request)
    {
        await ChatService.AddReactionAsync(request.MessageId, request.Emoji);
        // Refresh messages to show updated reactions
        if (selectedChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(selectedChannel.Id, 0, messages.Count);
        }
        StateHasChanged();
    }
}

