@using sv_29fc3e824fba45c59008af8e307b0bfe.Services
@inject IJSRuntime JS

<div class="message-area">
    @if (Channel is not null)
    {
        <div class="message-area-header">
            <h2># @Channel.Name</h2>
            <p>@Channel.Description</p>
        </div>

        <div class="message-list" @ref="messageListRef" @onscroll="HandleScroll">
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
            @foreach (var message in Messages)
            {
                <MessageItem Message="message"
                             ThreadReplyCount="GetThreadReplyCount(message.Id)"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                      ButtonLabel="Send"
                      OnSend="OnSendMessage" />
    }
    else
    {
        <div class="no-channel-selected">
            <p>Select a channel to start chatting</p>
        </div>
    }
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<Message> OnOpenThread { get; set; }
    [Parameter] public EventCallback<MessageItem.ReactionRequest> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;
    private bool scrolledToBottom = true;

    private int GetThreadReplyCount(int messageId)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
        return summary?.ReplyCount ?? 0;
    }

    private async Task HandleScroll()
    {
        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop <= 0 && !IsLoadingMore)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (scrolledToBottom)
        {
            await JS.InvokeVoidAsync("eval",
                "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
        }
    }
}

