.form-floating > .form-control-plaintext:focus::placeholder, .form-floating > .form-control:focus::placeholder {
    text-align: start;
}

/* Chat Layout */
.chat-layout {
    display: grid;
    grid-template-columns: 20% 1fr;
    height: calc(100vh - 3.5rem);
    overflow: hidden;
}

.chat-layout.thread-open {
    grid-template-columns: 20% 1fr 25%;
}

/* Channel Sidebar */
.channel-sidebar {
    background: #2c2f33;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    overflow-y: auto;
    border-right: 1px solid #202225;
}

.sidebar-title {
    padding: 1rem;
    margin: 0;
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #8e9297;
    border-bottom: 1px solid #202225;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
}

.channel-item {
    padding: 0.5rem 1rem;
    cursor: pointer;
    border-radius: 4px;
    margin: 2px 8px;
    display: flex;
    flex-direction: column;
    gap: 2px;
    position: relative;
}

.channel-item:hover {
    background: #34373c;
}

.channel-item.active {
    background: #393c43;
    color: #fff;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-description {
    font-size: 0.75rem;
    color: #8e9297;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    position: absolute;
    top: 50%;
    right: 0.75rem;
    transform: translateY(-50%);
    background: #ed4245;
    color: #fff;
    border-radius: 10px;
    padding: 0 6px;
    font-size: 0.7rem;
    font-weight: 700;
    min-width: 18px;
    text-align: center;
}

/* Message Area */
.message-area {
    display: flex;
    flex-direction: column;
    background: #36393f;
    color: #dcddde;
    overflow: hidden;
}

.message-area-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #202225;
    flex-shrink: 0;
}

.message-area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.message-area-header p {
    margin: 0.25rem 0 0;
    font-size: 0.8rem;
    color: #8e9297;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.loading-indicator {
    text-align: center;
    padding: 0.5rem;
    color: #8e9297;
    font-size: 0.85rem;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #8e9297;
}

/* Message Item */
.message-item {
    padding: 0.5rem 0.75rem;
    border-radius: 4px;
    position: relative;
}

.message-item:hover {
    background: #32353b;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.message-author {
    font-weight: 600;
    color: #fff;
    font-size: 0.9rem;
}

.message-time {
    font-size: 0.7rem;
    color: #72767d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.4;
    word-break: break-word;
}

.message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    background: #2f3136;
    border: 1px solid #4f545c;
    border-radius: 4px;
    padding: 2px 6px;
    font-size: 0.8rem;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: 4px;
}

.reaction-badge:hover {
    border-color: #7289da;
    background: #36393f;
}

.thread-link {
    font-size: 0.8rem;
    color: #7289da;
    cursor: pointer;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

/* Message Actions */
.message-actions {
    position: absolute;
    top: -8px;
    right: 0.5rem;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 2px;
}

.action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 0.75rem;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 3px;
}

.action-btn:hover {
    background: #36393f;
    color: #fff;
}

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    background: #2f3136;
    border: 1px solid #202225;
    border-radius: 4px;
    padding: 4px;
    display: flex;
    gap: 4px;
    z-index: 10;
}

.emoji-option {
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    font-size: 1.2rem;
}

.emoji-option:hover {
    background: #36393f;
}

/* Message Input Area */
.message-input-area {
    padding: 0.75rem 1rem;
    border-top: 1px solid #202225;
    display: flex;
    gap: 0.5rem;
    align-items: flex-end;
    flex-shrink: 0;
}

.message-textarea {
    flex: 1;
    background: #40444b;
    border: none;
    border-radius: 8px;
    padding: 0.6rem 1rem;
    color: #dcddde;
    font-size: 0.9rem;
    resize: none;
    outline: none;
}

.message-textarea:focus {
    box-shadow: none;
}

.send-button {
    background: #7289da;
    color: #fff;
    border: none;
    border-radius: 4px;
    padding: 0.5rem 1rem;
    font-size: 0.85rem;
    cursor: pointer;
    font-weight: 600;
}

.send-button:hover:not(:disabled) {
    background: #677bc4;
}

.send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* Thread Panel */
.thread-panel {
    background: #2f3136;
    color: #dcddde;
    display: flex;
    flex-direction: column;
    border-left: 1px solid #202225;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #202225;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
}

.close-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #36393f;
    color: #fff;
}

.thread-root-message {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #202225;
    background: #36393f;
    flex-shrink: 0;
}

.thread-root-message .message-author {
    font-size: 0.85rem;
}

.thread-root-message .message-content {
    margin-top: 0.25rem;
    font-size: 0.85rem;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.thread-reply-item {
    padding: 0.4rem 0.5rem;
    border-radius: 4px;
}

.thread-reply-item:hover {
    background: #32353b;
}

.form-floating > .form-control-plaintext:focus::placeholder, .form-floating > .form-control:focus::placeholder {
    text-align: start;
}

/* Chat Layout */
.chat-layout {
    display: grid;
